const articles = $input.first().json;
const body = Array.isArray(articles) ? (articles[0] && articles[0].body) : (articles.body || '');
const match = body && body.match(/Payload \(for approval workflow\):\s*({.+})/s);
const payload = match ? JSON.parse(match[1]) : null;
if (!payload || !payload.uid) throw new Error('No registration payload in ticket body');
const ticketId = $('Only If Cert-Reg + Approved').first().json.id;
return [{ json: { ...payload, ticket_id: ticketId } }];
